+    fn format_hotkeys(&self) -> String {
+        use crate::keybindings::ActionCategory;
+        use std::fmt::Write;
+
+        let mut output = String::new();
+        let _ = writeln!(output, "Keyboard Shortcuts");
+        let _ = writeln!(output, "==================");
+        let _ = writeln!(output);
+        let _ = writeln!(
+            output,
